import sys
from typing import List

class Solution:
    def countGreater(self, arr: List[int]) -> List[int]:
        n = len(arr)
        result = [0] * n
        sorted_arr = sorted(arr)
        j = n - 1
        for i in range(n - 1, -1, -1):
            while j >= 0 and sorted_arr[j] > arr[i]:
                j -= 1
            result[i] = n - 1 - j
        return result

if __name__ == '__main__':
