#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> countGreater(vector<int>& arr) {
        int n = arr.size();
        vector<int> result(n);
        vector<int> sorted_arr = arr;
        sort(sorted_arr.begin(), sorted_arr.end());
        int j = n - 1;
        for (int i = n - 1; i >= 0; --i) {
            while (j >= 0 && sorted_arr[j] > arr[i]) {
                --j;
            }
            result[i] = n - 1 - j;
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    Solution sol;
    vector<int> ans = sol.countGreater(arr);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
